import { useState, useRef, useEffect } from "react"
import { Button } from "../../components/ui/Button"
import { Upload, X, Check } from "lucide-react"

interface AvatarUploadProps {
  currentAvatar?: string
  onAvatarChange: (file: File) => void
  onRemove?: () => void
  isLoading?: boolean
}

const DEFAULT_AVATAR = "data:image/png;base64,"

export default function AvatarUpload({
  currentAvatar,
  onAvatarChange,
  onRemove,
  isLoading = false,
}: AvatarUploadProps) {
  const [preview, setPreview] = useState<string | null>(
    currentAvatar ?? null
  )
  const [pendingFile, setPendingFile] = useState<File | null>(null)
  const [tempPreview, setTempPreview] = useState<string | null>(null)
  const lastAvatarRef = useRef<string | undefined>(currentAvatar)
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Sync preview when currentAvatar changes (e.g., after upload success)
  useEffect(() => {
    if (currentAvatar !== lastAvatarRef.current) {
      setPreview(currentAvatar ?? null)
      if (pendingFile || tempPreview) {
        setPendingFile(null)
        setTempPreview(null)
      }
      lastAvatarRef.current = currentAvatar
    }
  }, [currentAvatar, pendingFile, tempPreview])

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file || !file.type.startsWith("image/")) return

    const reader = new FileReader()
    reader.onloadend = () => {
      setPendingFile(file)
      setTempPreview(reader.result as string)
    }
    reader.readAsDataURL(file)
  }

  const handleConfirmAvatar = () => {
    if (pendingFile && tempPreview) {
      // Keep tempPreview visible as pending until parent confirms success
      onAvatarChange(pendingFile)
    }
  }

  const handleCancelAvatar = () => {
    setPendingFile(null)
    setTempPreview(null)
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  const handleRemove = () => {
    if (onRemove) onRemove();
    setPreview(null)
    setTempPreview(null)
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  // Use pending preview or current avatar or default
  const displayAvatar = tempPreview || preview || DEFAULT_AVATAR

  return (
    <div className="flex flex-col items-center gap-4">
      {/* Avatar Display */}
      <div className="relative w-32 h-32">
        <div className="relative w-full h-full rounded-full overflow-hidden border-4 border-primary shadow-lg">
          <img
            src={displayAvatar}
            alt="Avatar preview"
            className="absolute inset-0 w-full h-full object-cover"
            referrerPolicy="no-referrer"
          />
        </div>

        {/* Remove Button - only show if there's a current avatar and no pending */}
        {!pendingFile && preview && !tempPreview && (
          <button
            type="button"
            onClick={handleRemove}
            className="absolute -top-2 -right-2 bg-red-500 hover:bg-red-600 text-white rounded-full p-1 transition-colors"
            title="Remove avatar"
            disabled={isLoading}
          >
            <X size={16} />
          </button>
        )}
      </div>

      {/* Action Buttons */}
      {!pendingFile ? (
        <>
          {/* Hidden File Input */}
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            onChange={handleFileSelect}
            className="hidden"
            aria-label="Upload avatar"
            disabled={isLoading}
          />

          {/* Upload Button */}
          <Button
            type="button"
            onClick={() => fileInputRef.current?.click()}
            variant="outline"
            className="border-primary text-primary hover:bg-secondary/50 gap-2"
            disabled={isLoading}
          >
            <Upload size={16} />
            {isLoading ? 'Uploading...' : preview ? "Change Avatar" : "Upload Avatar"}
          </Button>
        </>
      ) : (
        /* Confirm/Cancel Buttons */
        <div className="flex gap-2 w-full">
          <Button
            type="button"
            onClick={handleCancelAvatar}
            variant="outline"
            className="flex-1 gap-2"
            disabled={isLoading}
          >
            <X size={16} />
            Cancel
          </Button>
          <Button
            type="button"
            onClick={handleConfirmAvatar}
            className="flex-1 bg-green-600 hover:bg-green-700 text-white gap-2"
            disabled={isLoading}
          >
            <Check size={16} />
            Confirm
          </Button>
        </div>
      )}

      <p className="text-xs text-muted-foreground text-center">
        Supported formats: JPG, PNG, GIF (Max 5MB)
      </p>
    </div>
  )
}
